// 문제 페이지 생성
function createQuestionPages() {
    const elements = [];

    // 문제 제목
    elements.push(
        new Paragraph({
            spacing: { after: 400 },
            children: [new TextRun({ text: "문제", bold: true, size: 28 })]
        })
    );

    questions.forEach((q, index) => {
        // 문제 번호와 텍스트
        elements.push(
            new Paragraph({
                spacing: { before: 300, after: 150 },
                children: [
                    new TextRun({ text: `${q.number}. `, bold: true, size: 24 }),
                    new TextRun({ text: q.text, size: 24 })
                ]
            })
        );

        // 선택지
        const choiceLabels = ['①', '②', '③', '④'];
        q.choices.forEach((choice, i) => {
            elements.push(
                new Paragraph({
                    spacing: { after: 100 },
                    indent: { left: 360 },
                    children: [
                        new TextRun({ text: `${choiceLabels[i]} ${choice}`, size: 22 })
                    ]
                })
            );
        });

        // 5문제마다 페이지 나누기
        if ((index + 1) % 5 === 0 && index < questions.length - 1) {
            elements.push(new PageBreak());
        }
    });

    return elements;
}

